{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/Magius.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class Magius < Base\n      # ゲームシステムの識別子\n      ID = 'Magius'\n\n      # ゲームシステム名\n      NAME = 'MAGIUS'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'まきうす'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGETEXT\n        ■能力値判定　MA+x>=t        x:修正値 t:目標値\n        例)MA>=7: ダイスを2個振って、その結果を表示\n\n        ■技能値判定　MS+x>=t        x:修正値 t:目標値\n        例)MS>=7: ダイスを3個振って、そのうち上位2つを採用し、結果を表示\n\n      INFO_MESSAGETEXT\n\n      register_prefix('M[AS]')\n\n      def initialize(command)\n        super(command)\n\n        @sort_barabara_dice = true # バラバラロール（Bコマンド）でソート有\n      end\n\n      def eval_game_system_specific_command(command)\n        resolute_ability_action(command) ||\n          resolute_skill_action(command)\n      end\n\n      private\n\n      def with_symbol(number)\n        if number == 0\n          return \"\"\n        elsif number > 0\n          return \"+\#{number}\"\n        else\n          return number.to_s\n        end\n      end\n\n      # 能力値判定\n      # @param [String] command\n      # @return [Result]\n      def get_result_of_ability_action(total, _dice_add, target)\n        if total >= target\n          return Result.success(\"成功\")\n        else\n          return Result.failure(\"失敗\")\n        end\n      end\n\n      def resolute_ability_action(command)\n        m = /MA([+-]\\d+)*>=(\\d+)/.match(command)\n        return nil unless m\n\n        modify = m[1] ? Arithmetic.eval(m[1], @round_type) : 0\n        target = m[2].to_i\n\n        dices = @randomizer.roll_barabara(2, 6).sort\n        dice_text = dices.join(\",\")\n        dice_add = dices.sum\n        total = dice_add + modify\n\n        result = get_result_of_ability_action(total, dice_add, target)\n\n        sequence = [\n          \"(\#{command})\",\n          \"[\#{dice_text}]\#{with_symbol(modify)}\",\n          total,\n          result.text,\n        ].compact\n\n        result.text = sequence.join(\" ＞ \")\n\n        return result\n      end\n\n      # 技能値値判定\n      # @param [String] command\n      # @return [Result]\n      def get_result_of_skill_action(total, _dice_add, target)\n        if total >= target\n          return Result.success(\"成功\")\n        else\n          return Result.failure(\"失敗\")\n        end\n      end\n\n      def resolute_skill_action(command)\n        m = /MS([+-]\\d+)*>=(\\d+)/.match(command)\n        return nil unless m\n\n        modify = m[1] ? Arithmetic.eval(m[1], @round_type) : 0\n        target = m[2].to_i\n\n        dices = @randomizer.roll_barabara(3, 6).sort\n        dice_text = dices.join(\",\")\n        dice_add = dices[1].to_i + dices[2].to_i\n        total = dice_add + modify\n\n        result = get_result_of_skill_action(total, dice_add, target)\n\n        sequence = [\n          \"(\#{command})\",\n          \"[\#{dice_text}]\#{with_symbol(modify)}\",\n          total,\n          result.text,\n        ].compact\n\n        result.text = sequence.join(\" ＞ \")\n\n        return result\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:Magius>", "self", "register_prefix", "initialize", "command", "@sort_barabara_dice", "eval_game_system_specific_command", "$ret_or_1", "resolute_ability_action", "resolute_skill_action", "private", "with_symbol", "number", "0", ">", "to_s", "get_result_of_ability_action", "total", "_dice_add", "target", ">=", "Result", "success", "failure", "m", "match", "modify", "[]", "1", "Arithmetic", "eval", "@round_type", "2", "to_i", "dices", "@randomizer", "roll_barabara", "6", "sort", "dice_text", "join", "dice_add", "sum", "+", "result", "sequence", "text", "compact", "text=", "get_result_of_skill_action", "3", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAA